import{_ as s,o as a,c as n,a0 as o}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"Suspend & Unsuspend","description":"","frontmatter":{},"headers":[],"relativePath":"admin/suspend-subjects.md","filePath":"admin/suspend-subjects.md"}'),r={name:"admin/suspend-subjects.md"};function t(i,e,d,u,l,p){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="suspend-unsuspend" tabindex="-1">Suspend &amp; Unsuspend <a class="header-anchor" href="#suspend-unsuspend" aria-label="Permalink to &quot;Suspend &amp; Unsuspend&quot;">​</a></h1><p>This guide is for <code>Supreme Admin</code> users only.</p><p>This page explains the <strong>admin action</strong> of suspending or unsuspending a kingdom or alliance from the subscriptions dashboard. For what suspension feels like to users, and how cascade behavior works, see <a href="./../subscriptions/suspension.html">Suspension &amp; Limited Mode</a>.</p><blockquote><p>Screenshot placeholder: <code>subs-suspend.png</code> (S64)</p></blockquote><h2 id="where-you-do-this" tabindex="-1">Where you do this <a class="header-anchor" href="#where-you-do-this" aria-label="Permalink to &quot;Where you do this&quot;">​</a></h2><p>Open <a href="./subscriptions-dashboard.html">Subscriptions &amp; Usage Manager</a>, find the kingdom or alliance row, and use:</p><ul><li><strong>Suspend</strong> to pause writes</li><li><strong>Unsuspend</strong> to restore normal write access</li></ul><h2 id="what-the-current-modal-asks-for" tabindex="-1">What the current modal asks for <a class="header-anchor" href="#what-the-current-modal-asks-for" aria-label="Permalink to &quot;What the current modal asks for&quot;">​</a></h2><p>In the current UI, the suspend action asks for an optional <strong>message shown to affected users</strong>.</p><p>That message is useful for notes like:</p><ul><li>suspended pending payment</li><li>temporary admin hold</li><li>contact support before continuing</li></ul><h2 id="what-suspension-does" tabindex="-1">What suspension does <a class="header-anchor" href="#what-suspension-does" aria-label="Permalink to &quot;What suspension does&quot;">​</a></h2><p>Suspension blocks normal write actions for that subject while keeping read access available. The detailed user-facing effects, cascade behavior, and the special survival rule for directly subscribed alliances are already explained in <a href="./../subscriptions/suspension.html">Suspension &amp; Limited Mode</a>.</p><h2 id="about-reasons-and-overrides" tabindex="-1">About reasons and overrides <a class="header-anchor" href="#about-reasons-and-overrides" aria-label="Permalink to &quot;About reasons and overrides&quot;">​</a></h2><p>The backend tracks suspension reasons, and the broader suspension model includes override behavior in some cases, but those details are best understood from the platform suspension rules rather than from this action guide alone.</p><p>Use <a href="./../subscriptions/suspension.html">Suspension &amp; Limited Mode</a> as the source of truth for:</p><ul><li>cascade rules</li><li>usage-limit versus harder admin reasons</li><li>when an alliance can survive a parent suspension</li></ul><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Open the usage detail before suspending so you understand the current state.</li><li>Add a user-facing message when the pause needs explanation.</li><li>Unsuspend only after the underlying issue is actually resolved.</li></ul>',19)])])}const m=s(r,[["render",t]]);export{c as __pageData,m as default};
